using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the discriminator property from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator", so we must keep the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id format from "EntityType|Key" to just "Key".
            // Existing documents use "Product|123", so we must opt in to the legacy format.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.Internal.IdValueGenerator>();
        });
    }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Preserve the EF Core 8 "TypeName|KeyValue" id format for backward compatibility.
        // Without this, EF Core 9 generates ids as just "KeyValue", breaking reads of
        // existing documents whose id is "Product|123".
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

