class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe because we kept the discriminator as "Discriminator"
        // in OnModelCreating. Without that override EF Core 9 would write "$type" instead,
        // and this query would silently return zero rows.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider removed all synchronous APIs (ToList, First, Single, etc.).
        // Calls must be async; sync calls throw InvalidOperationException at runtime.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

