using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 writes "$type" instead of "Discriminator".
            // Existing 500K docs and raw SQL queries use "Discriminator".
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — id value format changed.
            // EF 8 wrote id as "Product|123"; EF 9 writes just "123".
            // We must keep the old format so reads of existing docs succeed.
            entity.Property<string>("__id")
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex is not supported on Cosmos.
            // EF 9 now throws; the previous HasIndex(p => p.Sku) was removed.
            // Manage indexes through the Azure portal or Cosmos SDK instead.
        });
    }
}

/// <summary>
/// Reproduces the EF Core 8 Cosmos id format: "EntityType|KeyValue".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    protected override string GenerateValue(EntityEntry entry)
    {
        var typeName = entry.Metadata.ShortName();
        var keyValues = entry.Metadata.FindPrimaryKey()!
            .Properties
            .Select(p => entry.Property(p.Name).CurrentValue)
            .Select(v => v?.ToString() ?? "");
        return $"{typeName}|{string.Join("|", keyValues)}";
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

